-- Name: obtener_estadisticas_cliente(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.obtener_estadisticas_cliente(p_id_cliente integer) RETURNS TABLE(total_gastado numeric, numero_compras bigint, promedio_compra numeric, ultima_compra timestamp without time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COALESCE(SUM(v.total), 0) as total_gastado,
    COUNT(DISTINCT v.id_venta) as numero_compras,
    CASE 
      WHEN COUNT(DISTINCT v.id_venta) = 0 THEN 0
      ELSE COALESCE(SUM(v.total), 0) / COUNT(DISTINCT v.id_venta)
    END as promedio_compra,
    MAX(v.fecha) as ultima_compra
  FROM ventas v
  WHERE v.id_cliente = p_id_cliente AND v.estado = 'registrada';
END;
$$;


