--
-- TOC entry 257 (class 1255 OID 34527)
-- Name: obtener_productos_proveedor(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.obtener_productos_proveedor(p_id_proveedor integer) RETURNS TABLE(id_producto integer, nombre character varying, precio numeric, stock integer, categoria_nombre character varying, es_principal boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    p.id_producto,
    p.nombre,
    p.precio,
    p.stock,
    c.nombre AS categoria_nombre,
    COALESCE(pp.es_principal, (p.id_proveedor = p_id_proveedor)) AS es_principal
  FROM productos p
  LEFT JOIN categorias c ON p.id_categoria = c.id_categoria
  LEFT JOIN proveedor_producto pp ON pp.id_producto = p.id_producto AND pp.id_proveedor = p_id_proveedor
  WHERE p.id_proveedor = p_id_proveedor 
     OR EXISTS (
       SELECT 1 FROM proveedor_producto 
       WHERE id_proveedor = p_id_proveedor AND id_producto = p.id_producto
     )
  ORDER BY es_principal DESC, p.nombre;
END;
$$;


