--

CREATE FUNCTION public.obtener_proveedores_producto(p_id_producto integer) RETURNS TABLE(id_proveedor integer, nombre character varying, telefono character varying, correo character varying, precio_compra numeric, es_principal boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    pr.id_proveedor,
    pr.nombre,
    pr.telefono,
    pr.correo,
    pp.precio_compra,
    COALESCE(pp.es_principal, (p.id_proveedor = pr.id_proveedor)) AS es_principal
  FROM productos p
  LEFT JOIN proveedores pr ON pr.id_proveedor = p.id_proveedor
  LEFT JOIN proveedor_producto pp ON pp.id_producto = p.id_producto AND pp.id_proveedor = pr.id_proveedor
  WHERE p.id_producto = p_id_producto AND pr.id_proveedor IS NOT NULL
  
  UNION
  
  SELECT 
    pr.id_proveedor,
    pr.nombre,
    pr.telefono,
    pr.correo,
    pp.precio_compra,
    pp.es_principal
  FROM proveedor_producto pp
  INNER JOIN proveedores pr ON pr.id_proveedor = pp.id_proveedor
  WHERE pp.id_producto = p_id_producto
  ORDER BY es_principal DESC, nombre;
END;
$$;


