-- Name: obtener_ultimas_compras_cliente(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.obtener_ultimas_compras_cliente(p_id_cliente integer, p_limite integer DEFAULT 10) RETURNS TABLE(id_venta integer, fecha timestamp without time zone, total numeric, metodo_pago character varying, estado character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    v.id_venta,
    v.fecha,
    v.total,
    v.metodo_pago,
    v.estado
  FROM ventas v
  WHERE v.id_cliente = p_id_cliente AND v.estado != 'anulada'
  ORDER BY v.fecha DESC
  LIMIT p_limite;
END;
$$;


