--
-- TOC entry 251 (class 1259 OID 34530)
-- Name: vista_estadisticas_clientes; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vista_estadisticas_clientes AS
 SELECT c.id_cliente,
    c.nombre,
    c.cedula,
    c.telefono,
    c.correo,
    c.direccion,
    c.activo,
    count(DISTINCT v.id_venta) AS numero_compras,
    COALESCE(sum(v.total), (0)::numeric) AS total_gastado,
        CASE
            WHEN (count(DISTINCT v.id_venta) = 0) THEN (0)::numeric
            ELSE (COALESCE(sum(v.total), (0)::numeric) / (count(DISTINCT v.id_venta))::numeric)
        END AS promedio_compra,
    max(v.fecha) AS ultima_compra
   FROM (public.clientes c
     LEFT JOIN public.ventas v ON (((c.id_cliente = v.id_cliente) AND ((v.estado)::text = 'registrada'::text))))
  GROUP BY c.id_cliente, c.nombre, c.cedula, c.telefono, c.correo, c.direccion, c.activo;


ALTER VIEW public.vista_estadisticas_clientes OWNER TO postgres;

