--
-- TOC entry 245 (class 1259 OID 34475)
-- Name: vista_productos; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vista_productos AS
 SELECT p.id_producto,
    p.nombre,
    p.descripcion,
    p.precio,
    p.stock,
    p.stock_minimo,
        CASE
            WHEN (p.stock <= p.stock_minimo) THEN true
            ELSE false
        END AS stock_bajo,
    c.nombre AS categoria,
    c.id_categoria,
    p.activo,
    p.fecha_creacion
   FROM (public.productos p
     LEFT JOIN public.categorias c ON ((p.id_categoria = c.id_categoria)));


ALTER VIEW public.vista_productos OWNER TO postgres;

