    pr.activo AS proveedor_activo
   FROM ((public.productos p
     LEFT JOIN public.categorias c ON ((p.id_categoria = c.id_categoria)))
     LEFT JOIN public.proveedores pr ON ((p.id_proveedor = pr.id_proveedor)));


