--
-- TOC entry 5166 (class 2618 OID 34525)
-- Name: vista_proveedores_completa _RETURN; Type: RULE; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW public.vista_proveedores_completa AS
 SELECT pr.id_proveedor,
    pr.nombre,
    pr.telefono,
    pr.correo,
    pr.producto AS producto_texto,
    pr.latitud,
    pr.longitud,
    pr.activo,
    pr.fecha_creacion,
    count(DISTINCT p.id_producto) AS total_productos,
    count(DISTINCT
        CASE
            WHEN (p.activo = true) THEN p.id_producto
            ELSE NULL::integer
        END) AS productos_activos,
    count(DISTINCT pp.id_producto) AS productos_relacionados
   FROM ((public.proveedores pr
     LEFT JOIN public.productos p ON ((p.id_proveedor = pr.id_proveedor)))
     LEFT JOIN public.proveedor_producto pp ON ((pp.id_proveedor = pr.id_proveedor)))
  GROUP BY pr.id_proveedor;


